import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.BnBoz4Zl.js";const o="/anjian-workbuddy-bluebook-site/assets/001_image_MuLCbdPyDo.CC7t9EuE.png",i="/anjian-workbuddy-bluebook-site/assets/002_image_DtASbQcrto.D8OmFDwj.png",n="/anjian-workbuddy-bluebook-site/assets/003_image_W7VqbwVeJo.1GRpiN8R.png",s="/anjian-workbuddy-bluebook-site/assets/004_image_JiigbkdTKo.DjMprcaA.png",y=JSON.parse('{"title":"第 3 章 WorkBuddy 的主界面、任务与工作区","description":"WorkBuddy 主界面可以理解为三个区域：左侧（侧边栏）管理任务，中间（对话区）下达和追踪任务，右侧（结果区）查看文件、变更、预览和最终产物。 工作目录既是效率设置，也是安全边界。把发票、周报、客户材料混在同一个大目录里，会增加误读、误改和信息串用的风险。","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md","lastUpdated":1783659790000}'),l={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 3 章 WorkBuddy 的主界面、任务与工作区/index.md"};function h(b,t,p,u,_,k){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="第-3-章-workbuddy-的主界面、任务与工作区" tabindex="-1">第 3 章 WorkBuddy 的主界面、任务与工作区 <a class="header-anchor" href="#第-3-章-workbuddy-的主界面、任务与工作区" aria-label="Permalink to &quot;第 3 章 WorkBuddy 的主界面、任务与工作区&quot;">​</a></h1><p>WorkBuddy 主界面可以理解为三个区域：左侧（侧边栏）管理任务，中间（对话区）下达和追踪任务，右侧（结果区）查看文件、变更、预览和最终产物。</p><p><img src="'+o+'" alt="" loading="lazy"></p><h2 id="三个区域分别做什么" tabindex="-1">三个区域分别做什么 <a class="header-anchor" href="#三个区域分别做什么" aria-label="Permalink to &quot;三个区域分别做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>主要用途</th><th>使用时重点检查</th></tr></thead><tbody><tr><td>侧边栏</td><td>新建、搜索、切换和管理任务</td><td>是否进入了正确任务</td></tr><tr><td>对话区</td><td>描述需求、补充信息、确认计划</td><td>目标和约束是否完整</td></tr><tr><td>结果区</td><td>查看产物、全部文件、变更与预览</td><td>文件名、路径和改动是否符合预期</td></tr></tbody></table><h2 id="为什么要隔离工作目录" tabindex="-1">为什么要隔离工作目录 <a class="header-anchor" href="#为什么要隔离工作目录" aria-label="Permalink to &quot;为什么要隔离工作目录&quot;">​</a></h2><p>工作目录既是效率设置，也是安全边界。把发票、周报、客户材料混在同一个大目录里，会增加误读、误改和信息串用的风险。</p><p>推荐按任务建目录空间。</p><p>同时，可以对目录空间的权限进行设置，当开启“允许完全访问”（开启完全访问后智能体可读写授权目录外文件，请谨慎使用并优先按任务限定目录。）</p><p><img src="'+i+'" alt="" loading="lazy"></p><h2 id="三种工作模式" tabindex="-1">三种工作模式 <a class="header-anchor" href="#三种工作模式" aria-label="Permalink to &quot;三种工作模式&quot;">​</a></h2><p>WorkBuddy 提供三种工作模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>中文界面</th><th>能做什么</th><th>适合场景</th></tr></thead><tbody><tr><td>Ask</td><td>问一问</td><td>问答、理解和查看，不修改文件</td><td>先了解资料、确认需求</td></tr><tr><td>Craft</td><td>做一做</td><td>可直接操作本地文件、运行代码及系统指令</td><td>路径清楚、风险较低的任务</td></tr><tr><td>Plan</td><td>想一想</td><td>先生成计划，确认后再执行</td><td>多步骤、跨系统、重要文件任务</td></tr></tbody></table><p><img src="'+n+'" alt="" loading="lazy"></p><h2 id="选择不同的模型" tabindex="-1">选择不同的模型 <a class="header-anchor" href="#选择不同的模型" aria-label="Permalink to &quot;选择不同的模型&quot;">​</a></h2><p>默认为自动模式，可以指定你想使用的模型，不同模型积分消耗不同。</p><p><img src="'+s+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>任务特征</th><th>优先关注</th></tr></thead><tbody><tr><td>大量文本与长资料</td><td>上下文长度，比如 100 万 tokens（1M）</td></tr><tr><td>图片与截图</td><td>需要有视觉理解能力</td></tr><tr><td>高频简单任务</td><td>优先选择响应速度快、成本较低的模型</td></tr></tbody></table>',18)])])}const m=d(l,[["render",h]]);export{y as __pageData,m as default};
